package com.games.entity;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Entity@Table(name = "riddles")@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Builderpublic class Riddle {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false, columnDefinition = "TEXT")    private String question;    @Column(nullable = false, columnDefinition = "TEXT")    private String answer;    @Column(columnDefinition = "TEXT")    private String hint;    @Enumerated(EnumType.STRING)    @Column(nullable = false)    private Difficulty difficulty;    @Enumerated(EnumType.STRING)    @Column(nullable = false)    private Category category;    @Column(name = "ai_generated")    @Builder.Default    private Boolean aiGenerated = true;    @Column(name = "created_at")    @Builder.Default    private LocalDateTime createdAt = LocalDateTime.now();    public enum Difficulty {        EASY, MEDIUM, HARD    }    public enum Category {        LOGIC, MATH, WORDPLAY, SCIENCE, GENERAL, RIDDLE    }}